@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly Dictionary<string, (string Label, string Icon)> Sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨"),
    };
}

@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="password-form mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }
            @if (ShowSuccess)
            {
                <div class="alert alert-success py-2">Password updated successfully!</div>
            }

            <button class="btn btn-primary" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool ShowSuccess;
    private bool IsSubmitting;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }
        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            ShowSuccess = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            ErrorMessage = ex.Message;
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

@if (IsVisible)
{
    <div class="modal-backdrop show" @onclick="HandleCancel"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="HandleCancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Device</strong> from <strong>@Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="HandleCancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="HandleConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool IsVisible { get; set; }
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task HandleConfirm() => await OnConfirm.InvokeAsync();
    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="appearance-preview card">
    <div class="card-header">
        <small class="text-muted">Live Preview</small>
    </div>
    <div class="card-body preview-body @ThemeClass @FontClass @(CompactMode ? "compact" : "")">
        <div class="preview-header">
            <strong>Sample Dashboard</strong>
            <span class="preview-badge">@Language</span>
        </div>
        <p class="preview-text">This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <div class="preview-card-title">Card Title</div>
            <div class="preview-card-content">Card content with your chosen theme and font size.</div>
        </div>
        <div class="preview-actions">
            <span class="btn btn-sm btn-primary">Primary</span>
            <span class="btn btn-sm btn-outline-secondary">Secondary</span>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public string Language { get; set; } = "English";
    [Parameter] public bool CompactMode { get; set; }

    private string ThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string FontClass => FontSize switch
    {
        "Small" => "preview-font-sm",
        "Large" => "preview-font-lg",
        _ => "preview-font-md"
    };
}

