@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Profile</h4>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="avatar-preview">
                <img src="@AvatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                <div class="small text-muted text-break">@AvatarUrl</div>
            </div>
        </div>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success py-2 mt-2">Profile saved successfully!</div>
    }

    <div class="mt-3 d-flex gap-2">
        <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="HandleDiscard">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter] public string DisplayName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string AvatarUrl { get; set; } = "";
    [Parameter] public string Bio { get; set; } = "";
    [Parameter] public EventCallback<(string DisplayName, string Email, string AvatarUrl, string Bio)> OnSave { get; set; }
    [Parameter] public EventCallback OnDiscard { get; set; }

    private bool IsSaving;
    private bool ShowSuccess;

    private async Task HandleSave()
    {
        IsSaving = true;
        ShowSuccess = false;
        try
        {
            await OnSave.InvokeAsync((DisplayName, Email, AvatarUrl, Bio));
            ShowSuccess = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private async Task HandleDiscard()
    {
        ShowSuccess = false;
        await OnDiscard.InvokeAsync();
    }
}

@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Notifications</h4>
    <hr />

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h6>Muted Channels</h6>
    <div class="channel-list mb-3">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel @(isMuted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success py-2">Notification preferences saved!</div>
    }

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
        @(IsSaving ? "Saving…" : "Save Preferences")
    </button>
</div>

@code {
    [Parameter] public bool EmailNotifications { get; set; }
    [Parameter] public bool PushNotifications { get; set; }
    [Parameter] public bool WeeklyDigest { get; set; }
    [Parameter] public List<string> MutedChannels { get; set; } = [];
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<(bool Email, bool Push, bool Digest, List<string> Muted)> OnSave { get; set; }

    private bool IsSaving;
    private bool ShowSuccess;

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        ShowSuccess = false;
        try
        {
            await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels)));
            ShowSuccess = true;
        }
        finally
        {
            IsSaving = false;
        }
    }
}

@using sv_59e696ed215f421182a2816165f61da8.Services
@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Security</h4>
    <hr />

    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />
    </div>

    <div class="mb-4">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => HandleTwoFactorToggle((bool)(e.Value ?? false))" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (LastPasswordChange.HasValue)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
