                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (LastPasswordChange.HasValue)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </small>
        }
    </div>

    <div class="mb-3">
        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        var isCurrent = session == Sessions.FirstOrDefault();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <RevokeSessionDialog IsVisible="@(SessionToRevoke is not null)"
                         Device="@(SessionToRevoke?.Device ?? "")"
                         Location="@(SessionToRevoke?.Location ?? "")"
                         OnConfirm="HandleRevokeConfirm"
                         OnCancel="HandleRevokeCancel" />
</div>

@code {
    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnTwoFactorToggle { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? SessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session) => SessionToRevoke = session;
    private void HandleRevokeCancel() => SessionToRevoke = null;

    private async Task HandleRevokeConfirm()
    {
        if (SessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
            SessionToRevoke = null;
        }
    }

    private async Task HandleTwoFactorToggle(bool enabled)
    {
        await OnTwoFactorToggle.InvokeAsync(enabled);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
