@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Profile</h4>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="avatar-preview">
                <img src="@AvatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                <div class="small text-muted text-break">@AvatarUrl</div>
            </div>
        </div>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success py-2 mt-2">Profile saved successfully!</div>
    }

    <div class="mt-3 d-flex gap-2">
        <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
            @(IsSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="HandleDiscard">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter] public string DisplayName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string AvatarUrl { get; set; } = "";
    [Parameter] public string Bio { get; set; } = "";
    [Parameter] public EventCallback<(string DisplayName, string Email, string AvatarUrl, string Bio)> OnSave { get; set; }
    [Parameter] public EventCallback OnDiscard { get; set; }

    private bool IsSaving;
    private bool ShowSuccess;

    private async Task HandleSave()
    {
        IsSaving = true;
        ShowSuccess = false;
        try
        {
            await OnSave.InvokeAsync((DisplayName, Email, AvatarUrl, Bio));
            ShowSuccess = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private async Task HandleDiscard()
    {
        ShowSuccess = false;
        await OnDiscard.InvokeAsync();
    }
}

