@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Notifications</h4>
    <hr />

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h6>Muted Channels</h6>
    <div class="channel-list mb-3">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel @(isMuted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success py-2">Notification preferences saved!</div>
    }

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
        @(IsSaving ? "Saving…" : "Save Preferences")
    </button>
</div>

@code {
    [Parameter] public bool EmailNotifications { get; set; }
    [Parameter] public bool PushNotifications { get; set; }
    [Parameter] public bool WeeklyDigest { get; set; }
    [Parameter] public List<string> MutedChannels { get; set; } = [];
    [Parameter] public List<string> AllChannels { get; set; } = [];
    [Parameter] public EventCallback<(bool Email, bool Push, bool Digest, List<string> Muted)> OnSave { get; set; }

    private bool IsSaving;
    private bool ShowSuccess;

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        ShowSuccess = false;
        try
        {
            await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels)));
            ShowSuccess = true;
        }
        finally
        {
            IsSaving = false;
        }
    }
}

