@using sv_59e696ed215f421182a2816165f61da8.Services
@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Security</h4>
    <hr />

    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />
    </div>

    <div class="mb-4">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => HandleTwoFactorToggle((bool)(e.Value ?? false))" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (LastPasswordChange.HasValue)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </small>
        }
    </div>

    <div class="mb-3">
        <h6>Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        var isCurrent = session == Sessions.FirstOrDefault();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <RevokeSessionDialog IsVisible="@(SessionToRevoke is not null)"
                         Device="@(SessionToRevoke?.Device ?? "")"
                         Location="@(SessionToRevoke?.Location ?? "")"
                         OnConfirm="HandleRevokeConfirm"
                         OnCancel="HandleRevokeCancel" />
</div>

@code {
    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnTwoFactorToggle { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? SessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session) => SessionToRevoke = session;
    private void HandleRevokeCancel() => SessionToRevoke = null;

    private async Task HandleRevokeConfirm()
    {
        if (SessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
            SessionToRevoke = null;
        }
    }

    private async Task HandleTwoFactorToggle(bool enabled)
    {
        await OnTwoFactorToggle.InvokeAsync(enabled);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@namespace sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings

<div class="settings-section">
    <h4>Appearance</h4>
    <hr />

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                               value="@theme" checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"font-{size}")"
                               value="@size" checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"font-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="Language">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@CompactMode"
                           @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            @if (ShowSuccess)
            {
                <div class="alert alert-success py-2">Appearance settings saved!</div>
            }

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
                @(IsSaving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <AppearancePreview Theme="@Theme" FontSize="@FontSize"
                               Language="@Language" CompactMode="@CompactMode" />
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public string Language { get; set; } = "English";
    [Parameter] public bool CompactMode { get; set; }
    [Parameter] public EventCallback<(string Theme, string FontSize, string Language, bool CompactMode)> OnSave { get; set; }

    private bool IsSaving;
    private bool ShowSuccess;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Korean", "Portuguese"];

    private async Task HandleSave()
    {
        IsSaving = true;
        ShowSuccess = false;
        try
        {
            await OnSave.InvokeAsync((Theme, FontSize, Language, CompactMode));
            ShowSuccess = true;
        }
        finally
        {
            IsSaving = false;
        }
    }
}

