    margin-bottom: 0.75rem;
}

::deep .preview-badge {
    font-size: 0.7em;
    padding: 0.2em 0.6em;
    background: #6c757d;
    color: #fff;
    border-radius: 10px;
}

::deep .preview-text {
    color: inherit;
    opacity: 0.8;
    margin-bottom: 0.75rem;
}

::deep .preview-card {
    background: rgba(0, 0, 0, 0.05);
    padding: 0.75rem;
    border-radius: 6px;
    margin-bottom: 0.75rem;
}

::deep .preview-dark .preview-card {
    background: rgba(255, 255, 255, 0.08);
