::deep .preview-card-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .preview-card-content {
    opacity: 0.7;
    font-size: 0.9em;
}

::deep .preview-actions {
    display: flex;
    gap: 0.5rem;
}

/* Session revoke dialog */
::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1040;
}

::deep .modal.d-block {
    z-index: 1050;
}

/* Channel list */
