@page "/settings"
@using sv_59e696ed215f421182a2816165f61da8.Services
@using sv_59e696ed215f421182a2816165f61da8.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="SetActiveSection" />

    <div class="settings-content">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "profile":
                    <ProfileSection DisplayName="@profile!.DisplayName"
                                    Email="@profile.Email"
                                    AvatarUrl="@profile.AvatarUrl"
                                    Bio="@profile.Bio"
                                    OnSave="HandleProfileSave"
                                    OnDiscard="HandleProfileDiscard" />
                    break;

                case "notifications":
                    <NotificationsSection EmailNotifications="@notifPrefs!.EmailNotifications"
                                          PushNotifications="@notifPrefs.PushNotifications"
                                          WeeklyDigest="@notifPrefs.WeeklyDigest"
                                          MutedChannels="@mutedChannels"
                                          AllChannels="@allChannels"
                                          OnSave="HandleNotificationsSave" />
                    break;

                case "security":
                    <SecuritySection TwoFactorEnabled="@security!.TwoFactorEnabled"
                                     LastPasswordChange="@security.LastPasswordChange"
                                     Sessions="@security.Sessions"
                                     OnChangePassword="HandleChangePassword"
                                     OnTwoFactorToggle="HandleTwoFactorToggle"
                                     OnRevokeSession="HandleRevokeSession" />
                    break;

                case "appearance":
                    <AppearanceSection Theme="@appearance!.Theme"
                                       FontSize="@appearance.FontSize"
                                       Language="@appearance.Language"
                                       CompactMode="@appearance.CompactMode"
                                       OnSave="HandleAppearanceSave" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string activeSection = "profile";
    private bool isLoading = true;

    private UserProfile? profile;
    private NotificationPrefs? notifPrefs;
    private List<string> mutedChannels = [];
    private List<string> allChannels = [];
    private SecuritySettings? security;
    private AppearanceSettings? appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        isLoading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        profile = profileTask.Result;
        notifPrefs = notifTask.Result;
        mutedChannels = new List<string>(notifPrefs.MutedChannels);
        allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];
        security = securityTask.Result;
        appearance = appearanceTask.Result;
    }

    private void SetActiveSection(string section) => activeSection = section;

    private async Task HandleProfileSave((string DisplayName, string Email, string AvatarUrl, string Bio) data)
    {
        profile = new UserProfile(data.DisplayName, data.Email, data.AvatarUrl, data.Bio);
        await SettingsService.SaveProfileAsync(profile);
    }

    private async Task HandleProfileDiscard()
    {
        profile = await SettingsService.GetProfileAsync();
    }

    private async Task HandleNotificationsSave((bool Email, bool Push, bool Digest, List<string> Muted) data)
    {
        notifPrefs = new NotificationPrefs(data.Email, data.Push, data.Digest, data.Muted);
        mutedChannels = new List<string>(data.Muted);
        await SettingsService.SaveNotificationPrefsAsync(notifPrefs);
    }

    private async Task HandleChangePassword((string Current, string New) data)
    {
        await SettingsService.ChangePasswordAsync(data.Current, data.New);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleTwoFactorToggle(bool enabled)
    {
        security = security! with { TwoFactorEnabled = enabled };
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleAppearanceSave((string Theme, string FontSize, string Language, bool CompactMode) data)
    {
        appearance = new AppearanceSettings(data.Theme, data.FontSize, data.Language, data.CompactMode);
        await SettingsService.SaveAppearanceAsync(appearance);
    }
}

